orphan_candidates = set\(\)
# All .md files \(including index.md, log.md\) as link sources
all_sources = []

for root, dirs, files in os.walk\('.'\):
    for f in files:
        if not f.endswith\('.md'\):
            continue
        full = os.path.join\(root, f\)
        all_sources.append\(full\)
