    bn = os.path.splitext\(os.path.basename\(p\)\)[0]
    basename_map.setdefault\(bn, []\).append\(p\)

all_basenames = set\(basename_map.keys\(\)\)

# Track incoming links \(from ALL .md files including index/log\)
